<template>
  <view class="region-picker">
    <view class="picker-mask" @click="close"></view>
    <view class="picker-panel">
      <view class="picker-header">
        <text class="picker-cancel" @click="close">取消</text>
        <text class="picker-confirm" @click="confirm">确定</text>
      </view>
      <view class="picker-body">
        <scroll-view class="picker-col" scroll-y v-if="provinces.length">
          <view
            v-for="item in provinces"
            :key="item.value"
            :class="['picker-item', selectedProvince === item.value ? 'active' : '']"
            @click="selectProvince(item)"
          >{{ item.label }}</view>
        </scroll-view>
        <scroll-view class="picker-col" scroll-y v-if="cities.length">
          <view
            v-for="item in cities"
            :key="item.value"
            :class="['picker-item', selectedCity === item.value ? 'active' : '']"
            @click="selectCity(item)"
          >{{ item.label }}</view>
        </scroll-view>
        <scroll-view class="picker-col" scroll-y v-if="districts.length">
          <view
            v-for="item in districts"
            :key="item.value"
            :class="['picker-item', selectedDistrict === item.value ? 'active' : '']"
            @click="selectDistrict(item)"
          >{{ item.label }}</view>
        </scroll-view>
      </view>
    </view>
  </view>
</template>

<script>
import { getRegionData } from '@/common/region-data.js'

export default {
  name: 'RegionPicker',
  props: {
    value: { type: Array, default: () => [] }
  },
  data() {
    const allRegions = getRegionData()
    return {
      provinces: allRegions,
      cities: [],
      districts: [],
      selectedProvince: '',
      selectedCity: '',
      selectedDistrict: '',
      provinceObj: null,
      cityObj: null,
      districtObj: null
    }
  },
  mounted() {
    if (this.value && this.value.length) {
      this.restoreSelection(this.value)
    }
  },
  methods: {
    restoreSelection(val) {
      if (val[0] && this.provinces.length) {
        const p = this.provinces.find(item => item.value === val[0] || item.label === val[0])
        if (p) {
          this.selectedProvince = p.value
          this.provinceObj = p
          this.cities = p.children || []
          if (val[1]) {
            const c = this.cities.find(item => item.value === val[1] || item.label === val[1])
            if (c) {
              this.selectedCity = c.value
              this.cityObj = c
              this.districts = c.children || []
              if (val[2]) {
                const d = this.districts.find(item => item.value === val[2] || item.label === val[2])
                if (d) {
                  this.selectedDistrict = d.value
                  this.districtObj = d
                }
              }
            }
          }
        }
      }
    },
    selectProvince(item) {
      this.selectedProvince = item.value
      this.provinceObj = item
      this.cities = item.children || []
      this.selectedCity = ''
      this.selectedDistrict = ''
      this.cityObj = null
      this.districtObj = null
      this.districts = []
    },
    selectCity(item) {
      this.selectedCity = item.value
      this.cityObj = item
      this.districts = item.children || []
      this.selectedDistrict = ''
      this.districtObj = null
    },
    selectDistrict(item) {
      this.selectedDistrict = item.value
      this.districtObj = item
    },
    confirm() {
      if (!this.selectedProvince) {
        uni.showToast({ title: '请选择省份', icon: 'none' })
        return
      }
      if (!this.selectedCity) {
        uni.showToast({ title: '请选择城市', icon: 'none' })
        return
      }
      if (!this.selectedDistrict) {
        uni.showToast({ title: '请选择区县', icon: 'none' })
        return
      }
      const result = {
        value: [this.selectedProvince, this.selectedCity, this.selectedDistrict],
        label: [
          this.provinceObj && this.provinceObj.label,
          this.cityObj && this.cityObj.label,
          this.districtObj && this.districtObj.label
        ],
        province: this.provinceObj && this.provinceObj.label,
        city: this.cityObj && this.cityObj.label,
        district: this.districtObj && this.districtObj.label
      }
      this.$emit('confirm', result)
      this.close()
    },
    close() {
      this.$emit('close')
    }
  }
}
</script>

<style lang="scss" scoped>
.region-picker, .picker-mask {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0; z-index: 999;
}
.picker-mask { background: rgba(0,0,0,0.5); }
.picker-panel {
  position: absolute; bottom: 0; left: 0; right: 0;
  background: #fff; border-radius: 20rpx 20rpx 0 0;
  max-height: 60vh; display: flex; flex-direction: column;
}
.picker-header {
  display: flex; justify-content: space-between;
  padding: 24rpx 30rpx; border-bottom: 1rpx solid #eee;
  .picker-cancel { color: #999; font-size: 28rpx; }
  .picker-confirm { color: #07c160; font-size: 28rpx; font-weight: bold; }
}
.picker-body { display: flex; flex: 1; overflow: hidden; }
.picker-col {
  flex: 1; height: 40vh;
  &:nth-child(2) { border-left: 1rpx solid #f0f0f0; }
  &:nth-child(3) { border-left: 1rpx solid #f0f0f0; }
}
.picker-item {
  padding: 24rpx 20rpx; font-size: 26rpx; color: #333;
  text-align: center; white-space: nowrap; overflow: hidden;
  text-overflow: ellipsis;
  &.active { color: #07c160; background: #e8f8ee; font-weight: bold; }
}
</style>
